    }

    private fun handleIncomingIntent(intent: Intent?) {
        if (intent == null) {
            showError("No intent received.")
            return
        }

        // Prevent intent hijacking: validate the intent action and category
        if (!isValidShareIntent(intent)) {
            Log.w(TAG, "Received invalid or potentially hijacked intent. Action: ${intent.action}, Type: ${intent.type}")
            showError("Invalid share intent received.")
            finish()
            return
        }

        when (intent.action) {
            Intent.ACTION_SEND -> {
                val mimeType = intent.type ?: ""
                when {
                    mimeType == "text/plain" -> handleSharedText(intent)
                    mimeType.startsWith("image/") -> handleSharedImage(intent)
                    else -> {
                        showError("Unsupported content type: $mimeType")
                    }
                }
            }
            Intent.ACTION_SEND_MULTIPLE -> {
                val mimeType = intent.type ?: ""
                if (mimeType.startsWith("image/")) {
                    handleSharedMultipleImages(intent)
                } else {
                    showError("Unsupported content type for multiple share: $mimeType")
                }
            }
            else -> {
                showError("Unsupported action: ${intent.action}")
            }
        }
    }

    /**
     * Validates that the incoming intent is a legitimate share intent.
     * Prevents intent hijacking by verifying action, categories, and type.
     */
    private fun isValidShareIntent(intent: Intent): Boolean {
        val action = intent.action

        // Only allow SEND and SEND_MULTIPLE actions
        if (action != Intent.ACTION_SEND && action != Intent.ACTION_SEND_MULTIPLE) {
            return false
        }

        val type = intent.type
        if (type.isNullOrEmpty()) {
            return false
        }

        // Validate that the MIME type is one we expect
        if (type != "text/plain" && !type.startsWith("image/")) {
            return false
        }

        // For image types, validate against allowed MIME types
        if (type.startsWith("image/") && type != "image/*" && type !in ALLOWED_IMAGE_MIME_TYPES) {
            return false
        }

        // Ensure the intent has the DEFAULT category or no explicit categories
        // (system share intents typically have DEFAULT category)
        val categories = intent.categories
        if (categories != null && categories.isNotEmpty()) {
            if (!categories.contains(Intent.CATEGORY_DEFAULT)) {
                return false
            }
        }

        // Validate that the calling package is not spoofing our own package
        // to prevent self-referential attacks
        val callingPackage = getCallingPackageName()
        if (callingPackage == packageName) {
            Log.w(TAG, "Rejecting self-referential share intent")
            return false
        }

        return true
    }

    /**
     * Gets the calling package name safely.
     */
    private fun getCallingPackageName(): String? {
        return if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.LOLLIPOP_MR1) {
            referrer?.host ?: callingPackage
        } else {
            callingPackage
        }
    }

    private fun handleSharedText(intent: Intent) {
        val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)

        if (sharedText.isNullOrBlank()) {
            showError("No text content found in shared data.")
            return
        }

        // Sanitize and validate text input
        val sanitizedText = sanitizeText(sharedText)

        if (sanitizedText.isEmpty()) {
            showError("Shared text content is empty after sanitization.")
            return
        }

        // Check if it's a URL
        val url = extractUrl(sanitizedText)
        if (url != null) {
            processSharedUrl(url, sanitizedText)
        } else {
            processSharedPlainText(sanitizedText)
        }
    }

    private fun sanitizeText(text: String): String {
        // Truncate to max length to prevent abuse
        val truncated = if (text.length > MAX_TEXT_LENGTH) {
            text.substring(0, MAX_TEXT_LENGTH)
        } else {
            text
        }

        // Remove null bytes and control characters (except newlines and tabs)
        return truncated.replace(Regex("[\\x00-\\x08\\x0B\\x0C\\x0E-\\x1F]"), "").trim()
    }

    private fun extractUrl(text: String): String? {
        val matcher = Patterns.WEB_URL.matcher(text)
        return if (matcher.find()) {
            val url = matcher.group()
            // Validate URL scheme to prevent javascript: or data: URI attacks
            if (isAllowedUrlScheme(url)) {
                url
            } else {
                null
            }
        } else {
            null
        }
    }

    private fun isAllowedUrlScheme(url: String): Boolean {
        val lowerUrl = url.lowercase()
        return lowerUrl.startsWith("http://") ||
                lowerUrl.startsWith("https://") ||
                // URLs without scheme (Patterns.WEB_URL matches these too)
                (!lowerUrl.contains("://") && !lowerUrl.startsWith("javascript:") &&
                        !lowerUrl.startsWith("data:") && !lowerUrl.startsWith("file:") &&
                        !lowerUrl.startsWith("content:"))
    }

    private fun processSharedUrl(url: String, fullText: String) {
        Log.i(TAG, "Received shared URL: $url")

        statusTextView.text = "Received shared URL"

        val urlTextView = TextView(this).apply {
            text = "URL: $url"
            textSize = 14f
            setPadding(0, 8, 0, 8)
            setTextIsSelectable(true)
        }
        containerLayout.addView(urlTextView)

        if (fullText != url) {
            val contextTextView = TextView(this).apply {
                text = "Full text: $fullText"
                textSize = 12f
                setPadding(0, 4, 0, 8)
                setTextIsSelectable(true)
            }
            containerLayout.addView(contextTextView)
        }

        // Process the URL (e.g., save to database, fetch metadata, etc.)
        onUrlProcessed(url)
    }

    private fun processSharedPlainText(text: String) {
        Log.i(TAG, "Received shared text (length: ${text.length})")

        statusTextView.text = "Received shared text"

        val textView = TextView(this).apply {
            this.text = "Shared text: $text"
            textSize = 14f
            setPadding(0, 8, 0, 8)
            setTextIsSelectable(true)
        }
        containerLayout.addView(textView)

        // Process the text
        onTextProcessed(text)
    }

    private fun handleSharedImage(intent: Intent) {
        val imageUri: Uri? = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
            intent.getParcelableExtra(Intent.EXTRA_STREAM, Uri::class.java)
        } else {
            @Suppress("DEPRECATION")
            intent.getParcelableExtra(Intent.EXTRA_STREAM)
        }

        if (imageUri == null) {
            showError("No image found in shared data.")
            return
        }

        if (!isValidContentUri(imageUri)) {
            showError("Invalid or unsafe image URI.")
            return
        }

        val mimeType = contentResolver.getType(imageUri)
        if (mimeType == null || mimeType !in ALLOWED_IMAGE_MIME_TYPES) {
            showError("Unsupported image type: $mimeType")
            return
        }

        processImage(imageUri, mimeType)
    }

    private fun handleSharedMultipleImages(intent: Intent) {
        val imageUris: ArrayList<Uri>? = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
            intent.getParcelableArrayListExtra(Intent.EXTRA_STREAM, Uri::class.java)
        } else {
            @Suppress("DEPRECATION")
            intent.getParcelableArrayListExtra(Intent.EXTRA_STREAM)
        }

        if (imageUris.isNullOrEmpty()) {
            showError("No images found in shared data.")
            return
        }

        if (imageUris.size > MAX_IMAGES) {
            showError("Too many images shared. Maximum is $MAX_IMAGES.")
            return
        }

        statusTextView.text = "Received ${imageUris.size} shared images"

        var processedCount = 0
        for (uri in imageUris) {
            if (!isValidContentUri(uri)) {
                Log.w(TAG, "Skipping invalid URI: $uri")
                continue
            }

            val mimeType = contentResolver.getType(uri)
            if (mimeType == null || mimeType !in ALLOWED_IMAGE_MIME_TYPES) {
                Log.w(TAG, "Skipping unsupported image type: $mimeType for URI: $uri")
                continue
            }

            processImage(uri, mimeType)
            processedCount++
        }

        if (processedCount == 0) {
            showError("No valid images could be processed.")
        } else {
            statusTextView.text = "Processed $processedCount of ${imageUris.size} images"
        }
    }

    /**
     * Validates that a URI is a safe content URI.
     * Prevents path traversal and access to unauthorized file system locations.
     */
    private fun isValidContentUri(uri: Uri): Boolean {
        val scheme = uri.scheme?.lowercase()

        // Only allow content:// URIs for security
        if (scheme != "content") {
            Log.w(TAG, "Rejected non-content URI scheme: $scheme")
            return false
        }

        // Check for path traversal attempts
        val path = uri.path ?: ""
        if (path.contains("..") || path.contains("//")) {
            Log.w(TAG, "Rejected URI with path traversal: $path")
            return false
        }

        // Verify we can actually access the URI
        return try {
            contentResolver.getType(uri) != null
        } catch (e: SecurityException) {
            Log.w(TAG, "SecurityException accessing URI: $uri", e)
            false
        } catch (e: Exception) {
            Log.w(TAG, "Exception accessing URI: $uri", e)
            false
        }
    }

    private fun processImage(uri: Uri, mimeType: String) {
        try {
            // Validate file size before processing
            val fileSize = getContentSize(uri)
            if (fileSize > MAX_IMAGE_SIZE_BYTES) {
                Log.w(TAG, "Image too large: $fileSize bytes (max: $MAX_IMAGE_SIZE_BYTES)")
                addErrorView("Image too large (${fileSize / 1024 / 1024}MB). Maximum size is ${MAX_IMAGE_SIZE_BYTES / 1024 / 1024}MB.")
                return
            }

            // Copy to app's private storage for safe processing
            val savedFile = copyToPrivateStorage(uri, mimeType)

            if (savedFile != null) {
                Log.i(TAG, "Image saved to: ${savedFile.absolutePath}")

                if (statusTextView.text == "") {
                    statusTextView.text = "Received shared image"
                }

                val imageView = ImageView(this).apply {
                    layoutParams = LinearLayout.LayoutParams(
                        LinearLayout.LayoutParams.MATCH_PARENT,
                        600
                    ).apply {
                        setMargins(0, 8, 0, 8)
                    }
                    scaleType = ImageView.ScaleType.FIT_CENTER
                    adjustViewBounds = true
                    setImageURI(Uri.fromFile(savedFile))
                }
                containerLayout.addView(imageView)

                val infoTextView = TextView(this).apply {
                    text = "Type: $mimeType | Size: ${savedFile.length() / 1024}KB | Saved: ${savedFile.name}"
                    textSize = 12f
                    setPadding(0, 4, 0, 16)
                }
                containerLayout.addView(infoTextView)

                // Further processing
                onImageProcessed(savedFile, mimeType)
            } else {
                addErrorView("Failed to save image.")
            }
        } catch (e: SecurityException) {
            Log.e(TAG, "Security exception processing image", e)
            addErrorView("Permission denied accessing the shared image.")
        } catch (e: Exception) {
            Log.e(TAG, "Error processing shared image", e)
            addErrorView("Error processing image: ${e.message}")
        }
    }

    private fun getContentSize(uri: Uri): Long {
        return try {
            contentResolver.openAssetFileDescriptor(uri, "r")?.use {
                it.length
            } ?: 0L
        } catch (e: Exception) {
            Log.w(TAG, "Could not determine content size for URI: $uri", e)
            // If we can't determine size, allow it but check during copy
            0L
        }
    }

    private fun copyToPrivateStorage(uri: Uri, mimeType: String): File? {
        val extension = when (mimeType) {
            "image/jpeg" -> ".jpg"
            "image/png" -> ".png"
            "image/gif" -> ".gif"
            "image/webp" -> ".webp"
            "image/bmp" -> ".bmp"
            else -> ".img"
        }

        val fileName = "shared_${System.currentTimeMillis()}$extension"
        val outputDir = File(filesDir, "shared_images")
        if (!outputDir.exists()) {
            outputDir.mkdirs()
        }

        val outputFile = File(outputDir, fileName)

        // Ensure the output file is within our expected directory (prevent path traversal)
        if (!outputFile.canonicalPath.startsWith(outputDir.canonicalPath)) {
            Log.e(TAG, "Path traversal detected in output file")
            return null
        }

        var inputStream: InputStream? = null
        var outputStream: FileOutputStream? = null

        return try {
            inputStream = contentResolver.openInputStream(uri)
            if (inputStream == null) {
                Log.e(TAG, "Could not open input stream for URI: $uri")
                return null
            }

            outputStream = FileOutputStream(outputFile)

            val buffer = ByteArray(8192)
            var bytesRead: Int
            var totalBytesRead = 0L

            while (inputStream.read(buffer).also { bytesRead = it } != -1) {
                totalBytesRead += bytesRead
                if (totalBytesRead > MAX_IMAGE_SIZE_BYTES) {
                    Log.w(TAG, "Image exceeded max size during copy")
                    outputFile.delete()
                    return null
                }
                outputStream.write(buffer, 0, bytesRead)
            }

            outputStream.flush()
            outputFile
        } catch (e: Exception) {
            Log.e(TAG, "Error copying file to private storage", e)
            outputFile.delete()
            null
        } finally {
            try { inputStream?.close() } catch (_: Exception) {}
            try { outputStream?.close() } catch (_: Exception) {}
        }
    }

    /**
     * Called when a URL has been successfully extracted and validated.
     * Override or modify this to implement your business logic.
     */
    private fun onUrlProcessed(url: String) {
        Log.i(TAG, "URL processed: $url")
