    private fun showError(message: String) {
        Log.e(TAG, message)
        statusTextView.text = "Error: $message"
        Toast.makeText(this, message, Toast.LENGTH_LONG).show()
    }

    private fun addErrorView(message: String) {
        val errorView = TextView(this).apply {
            text = "⚠ $message"
            textSize = 12f
            setPadding(0, 4, 0, 8)
            setTextColor(resources.getColor(android.R.color.holo_red_dark, theme))
        }
        containerLayout.addView(errorView)
    }

    override fun onDestroy() {
        super.onDestroy()
        // Clean up old shared files (older than 24 hours)
        cleanupOldSharedFiles()
    }

    private fun cleanupOldSharedFiles() {
        try {
            val sharedDir = File(filesDir, "shared_images")
            if (sharedDir.exists()) {
                val cutoffTime = System.currentTimeMillis() - (24 * 60 * 60 * 1000)
                sharedDir.listFiles()?.forEach { file ->
                    if (file.lastModified() < cutoffTime) {
                        file.delete()
                    }
                }
            }
        } catch (e: Exception) {
            Log.w(TAG, "Error cleaning up shared files", e)
        }
    }
